        id: "faulthandler-segfault",
        fn: "faulthandler — Python traceback on segfault / hang",
        desc: "Stdlib module that installs C-level signal handlers so SIGSEGV / SIGFPE / hangs print a Python traceback to stderr. Essential when a C extension crashes or a process locks up.",
        category: "Error Handling",
